option.value:
// Package validator valida direcciones de email usando la librería estándar
// de Go `net/mail`, que implementa el parser de direcciones de RFC 5322.
//
// Se exige que la entrada sea una addr-spec pura (sin display-name ni
// comentarios CFWS), por lo que verificamos que el resultado de ParseAddress
// coincide con la entrada y no incluye nombre.
package validator

import (
	"net/mail"
	"strings"
)

// IsValid devuelve true si s es una dirección de email válida según RFC 5322
// usando el parser de net/mail. Adicionalmente:
//
//   - Rechaza formatos con display-name (`Nombre <addr@host>`).
//   - Exige al menos un punto en el dominio (descarta `user@host`, que el
//     parser acepta pero no es una dirección enrutable en la práctica).
func IsValid(s string) bool {
	if s == "" {
		return false
	}
	addr, err := mail.ParseAddress(s)
	if err != nil {
		return false
	}
	if addr.Name != "" || addr.Address != s {
		return false
	}
	at := strings.LastIndex(s, "@")
	if at < 0 {
		return false
	}
	domain := s[at+1:]
	if !strings.Contains(domain, ".") {
		return false
	}
	return true
}

package validator

import "testing"

// TestValidEmails comprueba direcciones que deben considerarse válidas.
func TestValidEmails(t *testing.T) {
	valid := []string{
		"simple@example.com",
		"very.common@example.com",
		"disposable.style.email.with+symbol@example.com",
		"other.email-with-hyphen@example.com",
		"fully-qualified-domain@example.com",
		"user.name+tag+sorting@example.com",
		"x@example.com",
		"example-indeed@strange-example.com",
		"test/test@test.com",
		"!#$%&'*+-/=?^_`{|}~@example.com",
		"user@mail.subdomain.example.com",
		"user@123.example.com",
		"1234567890@example.com",
	}
	for _, e := range valid {
		t.Run(e, func(t *testing.T) {
			if !IsValid(e) {
				t.Errorf("se esperaba VÁLIDO: %q", e)
			}
		})
	}
}

// TestInvalidEmails comprueba direcciones que deben rechazarse.
func TestInvalidEmails(t *testing.T) {
	invalid := []string{
		"",
		"plainaddress",
		"@no-local-part.com",
		"no-at-sign.com",
		"user@",
		"user@@example.com",
		"user@.com",
		"user@example",
		".user@example.com",
		"user.@example.com",
		"us..er@example.com",
		"user name@example.com",
		"user@exam ple.com",
		"user@example..com",
		`"unterminated@example.com`,
		`"@example.com`,
		"John Doe <john@example.com>",
	}
	for _, e := range invalid {
		t.Run(e, func(t *testing.T) {
			if IsValid(e) {
				t.Errorf("se esperaba INVÁLIDO: %q", e)
			}
		})
	}
}
